def convert_to_netscape(cookies):
    lines = ["# Netscape HTTP Cookie File"]
    for cookie in cookies:
        domain = cookie.get("domain", "")
        # Netscape format requires domain to start with . for subdomains, but let's just use what's there
        flag = "TRUE" if cookie.get("hostOnly") == False else "FALSE" # This flag is actually 'include subdomains'
        # Wait, standard is: domain, include_subdomains (TRUE/FALSE), path, secure (TRUE/FALSE), expiration, name, value
        
        # hostOnly=False means it applies to subdomains -> TRUE
        include_subdomains = "TRUE" if not cookie.get("hostOnly") else "FALSE"
        path = cookie.get("path", "/")
        secure = "TRUE" if cookie.get("secure") else "FALSE"
        expiration = str(int(cookie.get("expirationDate", 0)))
        name = cookie.get("name", "")
        value = cookie.get("value", "")
        
        lines.append(f"{domain}\t{include_subdomains}\t{path}\t{secure}\t{expiration}\t{name}\t{value}")
    return "\n".join(lines)

